import React, { useState } from 'react';

const App = () => {
  const [tasks, setTasks] = useState([{
    id: 1,
    name: 'Task 1',
    completed: false
  }, {
    id: 2,
    name: 'Task 2',
    completed: false
  }, {
    id: 3,
    name: 'Task 3',
    completed: false
  }]);
  const [newTaskName, setNewTaskName] = useState('');

  const handleTaskToggle = (id) => {
    setTasks(tasks.map(task => task.id === id ? {
      ...task,
      completed: !task.completed
    } : task));
  };

  const handleTask Removal = (id) => {
    setTasks(tasks.filter(task => task.id !== id));
  };

  const handleAddTask = () => {
    if (newTaskName.trim() !== '') {
      setTasks([...tasks, {
        id: tasks.length + 1,
        name: newTaskName,
        completed: false
      }]);
      setNewTaskName('');
    }
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-full max-w-lg bg-[#C06C88] p-4 rounded-md">
        <h2 className="text-2xl font-bold mb-4">Daily Task List</h2>
        <ul className="mb-4 list-none">
          {tasks.map((task, index) => (
            <li key={task.id} className="mb-2 flex items-center">
              <input
                type="checkbox"
                checked={task.completed}
                onChange={() => handleTaskToggle(task.id)}
                className="mr-2"
              />
              <span className="mr-2">{task.name}</span>
              <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded-md" onClick={() => handleTaskRemoval(task.id)}>Remove</button>
            </li>
          ))}
        </ul>
        <input
          type="text"
          value={newTaskName}
          onChange={(e) => setNewTaskName(e.target.value)}
          placeholder="Add new task"
          className="bg-transparent border-b border-white w-full p-2 text-lg"
        />
        <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded-md" onClick={handleAddTask}>Add Task</button>
      </div>
    </div>
  );
};

export default App;
